import numpy as npclass MonteCarloEngine:    def __init__(self, S0, r, sigma, T, steps, paths, option_type='asian_call'):        """        Initialize the Monte Carlo Simulation Engine.                Parameters:        S0 (float): Initial asset price        r (float): Risk-free interest rate        sigma (float): Volatility        T (float): Time to maturity (in years)        steps (int): Number of time steps along the path        paths (int): Number of independent trajectories to simulate        option_type (str): Type of option payoff ('asian_call')        """        self.S0 = S0        self.r = r        self.sigma = sigma        self.T = T        self.steps = steps        self.paths = paths        self.dt = T / steps        self.option_type = option_type    def generate_paths(self, custom_S0=None):        """        Simulates asset price paths using vectorized GBM paired with Antithetic Variates.        """        spot = custom_S0 if custom_S0 is not None else self.S0                # Enforce half the base paths since Antithetic generates pairs        half_paths = self.paths // 2                # Standard normal random variables        Z = np.random.normal(0, 1, (half_paths, self.steps))        # Concatenate random numbers with their negative counterparts (Antithetic Variates)        Z_full = np.vstack((Z, -Z))                # Vectorized path growth components        drift = (self.r - 0.5 * self.sigma**2) * self.dt        diffusion = self.sigma * np.sqrt(self.dt) * Z_full                # Compute structural logarithmic returns matrix        log_returns = drift + diffusion                # Prepend column of zeros representing the starting point t=0        log_returns = np.hstack((np.zeros((self.paths, 1)), log_returns))                # Cumulative sum to construct the dynamic price matrix trajectory        price_paths = spot * np.exp(np.cumsum(log_returns, axis=1))                return price_paths    def price_option(self, K, custom_S0=None):        """        Calculates the discounted expected payoff for specified exotic structures.        """        paths = self.generate_paths(custom_S0=custom_S0)        discount_factor = np.exp(-self.r * self.T)                if self.option_type == 'asian_call':            # Path-Dependent: Arithmetic average across all observed time horizons            average_prices = np.mean(paths[:, 1:], axis=1)            payoffs = np.maximum(average_prices - K, 0)        else:            raise ValueError(f"Option type '{self.option_type}' is not supported.")                    price = discount_factor * np.mean(payoffs)        standard_error = np.std(payoffs) / np.sqrt(self.paths)                return price, standard_error    def calculate_greeks(self, K, bump_pct=0.01):        """        Calculates Delta and Gamma using Finite Difference Method (Dynamic Re-simulation)        """        bump = self.S0 * bump_pct                # Re-price under perturbed conditions        price_up, _ = self.price_option(K, custom_S0=self.S0 + bump)        price_down, _ = self.price_option(K, custom_S0=self.S0 - bump)        price_base, _ = self.price_option(K, custom_S0=self.S0)                # Central Difference Delta        delta = (price_up - price_down) / (2 * bump)                # Second-order Derivative Central Difference Gamma        gamma = (price_up - 2 * price_base + price_down) / (bump ** 2)                return delta, gamma